# scripts/scan_flag_usage.py
import ast, pathlib, sys, json

def scan_for_flag(root: str, flag_id: str) -> list[dict]:
    """Find all evaluation sites for a specific flag."""
    results = []
    for path in pathlib.Path(root).rglob("*.py"):
        try:
            tree = ast.parse(path.read_text(), filename=str(path))
        except SyntaxError:
            continue

        for node in ast.walk(tree):
            # Match: flags.get_bool("genai.some.flag") or similar
            if isinstance(node, ast.Call):
                func = node.func
                if isinstance(func, ast.Attribute) and func.attr in (
                    "get_bool", "get_string", "get_float", "is_enabled"
                ):
                    args = node.args
                    if args and isinstance(args[0], ast.Constant):
                        if args[0].value == flag_id:
                            results.append({
                                "file": str(path),
                                "line": node.lineno,
                                "call": ast.unparse(node),
                            })
    return results

if __name__ == "__main__":
    flag_id = sys.argv[1]         # e.g. "genai.reasoning.advanced"
    src_root = sys.argv[2]        # e.g. "src/"
    hits = scan_for_flag(src_root, flag_id)
    print(json.dumps(hits, indent=2))
    print(f"\n{len(hits)} call site(s) found for flag '{flag_id}'")

